VALUES
  ('elementary-6f0ba476-moex-00314', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '關於證券交易稅條例，下列敘述何者錯誤？', '["證券交易稅由代徵人於每次買賣交割之當日，按規定稅率代徵，並於代徵之次日，填具繳款書向國 庫繳納", "代徵人依照法定程序及期限完成其代徵義務者，該管稽徵機關應按其代徵稅額給與千分之一之獎 金。但每一代徵人每年以新臺幣2400萬元為限", "證券交易稅向買受有價證券人按每次交易成交價格課徵", "證券發行公司於分派盈餘時，對於無記名股東，應先行公告通知辦理登記，並將無記名股東之姓 名、地址、國民身分證字號及分派盈餘數額等，列具清單，報告該管稽徵機關"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00315', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依財政收支劃分法之規定，下列何者不是國稅？', '["貨物稅", "菸酒稅", "契稅", "遺產及贈與稅"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00316', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依財政收支劃分法規定，在直轄市或鄉（鎮、市）徵起之遺產及贈與稅，應分別按稅收之多少比例， 分配給該直轄市或鄉（鎮、市）？', '["直轄市10%、鄉（鎮、市）50%", "直轄市40%、鄉（鎮、市）80%", "直轄市50%、鄉（鎮、市）80%", "直轄市50%、鄉（鎮、市）100%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00317', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依稅捐稽徵法有關納稅義務之規定，下列何者錯誤？', '["共有財產未設管理人且為公同共有時，由共有人各按其應有部分負納稅義務", "法人、合夥或非法人團體解散清算時，清算人於分配賸餘財產前，應依法按稅捐受清償之順序，繳 清稅捐", "納稅義務人死亡，遺有財產者，其依法應繳納之稅捐，應由遺囑執行人、繼承人、受遺贈人或遺產 管理人，依法按稅捐受清償之順序，繳清稅捐", "營利事業因合併而消滅時，其在合併前之應納稅捐，應由合併後存續或另立之營利事業負繳納之義務"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00318', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依稅捐稽徵法規定，下列敘述何者正確？', '["本法所稱稅捐，指一切法定之國、直轄市、縣（市）、鄉（鎮、市）稅捐及關稅", "財政部依稅法所發布之解釋函令，對於據以申請之案件發生效力。但有利於納稅義務人者，對於已 核課確定之案件適用之", "財政部發布解釋函令，變更已發布解釋函令之法令見解，如不利於納稅義務人者，自發布日起或財 政部指定之將來一定期日起，發生效力", "財政部發布之稅務違章案件裁罰金額或倍數參考表變更時，有利於納稅義務人者，對於已核課確定 案件適用之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00319', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '有關稅捐稽徵法分期繳納相關規定，下列何者正確？', '["核准分期繳納之期間最長為2年", "稅款應依臺灣銀行一年期定期儲蓄存款固定利率，按日加計利息一併徵收", "核准分期繳納之稅款不論金額大小，均應提供相當擔保", "任何一期應繳稅捐未如期繳納，應就未繳清之餘額稅款一次全部繳清"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00320', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '乙君112年7月出售一筆房屋及土地，該房地於111年12月因父親過世而繼承取得，乙父親106年 1月買入該房地，請問乙君出售房地適用之房地合一所得稅課稅稅率為何？', '["45%", "35%", "20%", "15%"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00321', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依所得稅法規定，個人取得下列類型所得，何者不是採用扣繳稅款分離課稅方式？', '["投資公司債之利息所得", "百貨公司抽獎之中獎獎金", "公益彩券大樂透之中獎獎金", "檢舉違反廢棄物清理之獎勵金"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00322', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '依所得稅法規定，適用勞動基準法之營利事業，依勞工退休金條例提繳之勞工退休金或年金保險費， 每年度得在不超過當年度已付薪資總額多少百分比限度內列支費用？', '["4%", "6%", "8%", "15%"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL),
  ('elementary-6f0ba476-moex-00323', 'elementary-6f0ba476', 'elementary-6f0ba476-moex-113-1eb3eaad', 'sub-elementary-6f0ba476-03', NULL, 'single_choice', '營利事業繳納各種稅法規定項目，申報營利事業所得稅時，下列何者可以列為費用或損失？', '["滯報金", "滯納利息", "滯納金", "罰鍰"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:30:39+00:00", "source_pdf_sha1": "9fa47c0220d7", "answer_pdf_sha1": "d884b4a395ab", "source_family": "moex-gov-tw", "moex": {"exam_code": "113010", "c": "507", "s": "0501", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "稅務法規大意", "year": "113", "exam_name": "113年公務人員初等考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "civil_slug": "elementary", "civil_category": "財稅行政"}'::jsonb, NULL)
